export function buildQMapSystemPrompt({
  locale = 'en',
  strictMode = true
}: QMapPromptOptions = {}): string {
  const isIt = String(locale).toLowerCase().startsWith('it');
  const lines = [
    ...(isIt ? IT_PRIORITY_LINES : EN_PRIORITY_LINES),
    ...(isIt ? IT_OPERATIONAL_POLICY_LINES : EN_OPERATIONAL_POLICY_LINES),
    ...(isIt ? IT_BASE_LINES : EN_BASE_LINES)
  ];

  if (strictMode) {
    lines.unshift(
      isIt
        ? 'Per ogni richiesta operativa sulla mappa esegui i tool necessari, poi fermati appena l obiettivo e soddisfatto; non dichiarare successo senza almeno un tool completato.'
        : 'For every map operation request, run required tool calls, then stop as soon as objective is satisfied; do not claim success without at least one completed tool call.'
    );
  } else {
    lines.unshift(
      isIt
        ? 'Quando opportuno puoi rispondere in modo descrittivo, ma per modificare la mappa usa i tool.'
        : 'When appropriate you can answer descriptively, but use tools for map modifications.'
    );
  }

  const seen = new Set<string>();
  const dedupedLines = lines.filter(rawLine => {
    const line = String(rawLine || '').trim();
    if (!line || seen.has(line)) return false;
    seen.add(line);
    return true;
  });

  return dedupedLines.join(' ');
}

export const QMAP_SYSTEM_PROMPT = buildQMapSystemPrompt();
